// nodes/mergeNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const MergeNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [strategy, setStrategy] = useState(data?.strategy ?? 'concat');
  const [separator, setSeparator] = useState(data?.separator ?? '\n\n');

  return (
    <BaseNode
      id={id}
      title="Merge"
      icon="🔀"
      accentColor="#4ade80"
      inputs={[
        { id: 'a', label: 'a' },
        { id: 'b', label: 'b' },
        { id: 'c', label: 'c' },
      ]}
      outputs={[{ id: 'merged', label: 'merged' }]}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Strategy</label>
        <select
          style={fieldStyle.select}
          value={strategy}
          onChange={(e) => {
            setStrategy(e.target.value);
            updateNodeField(id, 'strategy', e.target.value);
          }}
        >
          <option value="concat">Concatenate</option>
          <option value="json">JSON Array</option>
          <option value="template">Template</option>
          <option value="first">First Non-Empty</option>
        </select>
      </div>
      {strategy === 'concat' && (
        <div style={fieldStyle.group}>
          <label style={fieldStyle.label}>Separator</label>
          <input
            style={fieldStyle.input}
            value={separator}
            onChange={(e) => {
              setSeparator(e.target.value);
              updateNodeField(id, 'separator', e.target.value);
            }}
          />
        </div>
      )}
    </BaseNode>
  );
};
